namespace BlazorApp.Models;

public class EquipmentItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

using BlazorApp.Models;

namespace BlazorApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Forklift A",        Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 15) },
            new() { Id = 2, Name = "Conveyor Belt B",   Location = "Warehouse 2", LastInspected = new DateTime(2026, 4, 22) },
            new() { Id = 3, Name = "CNC Mill C",        Location = "Shop Floor",  LastInspected = new DateTime(2026, 1, 10) },
            new() { Id = 4, Name = "Hydraulic Press D", Location = "Shop Floor",  LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 5, Name = "Welding Robot E",   Location = "Assembly Bay", LastInspected = new DateTime(2025, 12, 5) },
            new() { Id = 6, Name = "Pallet Jack F",     Location = "Warehouse 1", LastInspected = new DateTime(2026, 2, 18) },
            new() { Id = 7, Name = "Air Compressor G",  Location = "Utility Room", LastInspected = new DateTime(2026, 4, 30) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@attribute [StreamRendering]
@using BlazorApp.Models
@using BlazorApp.Services
@inject EquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;
    private PersistingComponentStateSubscription persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        // Try to restore data persisted during prerender; if found, skip the service call.
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("inventory", out var restored))
        {
            items = restored;
        }
        else
        {
            items = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("inventory", items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        persistingSubscription.Dispose();
    }
}

